---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}
const { title = 'Dota 2 Merch — Официальный мерч', description = 'Оригинальный мерч по Dota 2: одежда, фигурки, аксессуары. Доставка по России и СНГ.' } = Astro.props;
---

---
import Layout from '../layouts/Layout.astro';
---

:root {
  --bg-deep: #0a0e14;
  --bg-card: #111820;
  --bg-elevated: #161d28;
  --border: #1e2a38;
  --text: #e2e8f0;
  --text-muted: #94a3b8;
  --accent-teal: #2dd4bf;
  --accent-teal-dim: #14b8a6;
  --accent-gold: #fbbf24;
  --accent-gold-dim: #f59e0b;
  --accent-blue: #38bdf8;
  --glow-teal: rgba(45, 212, 191, 0.25);
  --glow-gold: rgba(251, 191, 36, 0.2);
  --font-display: 'Orbitron', sans-serif;
  --font-body: 'Exo 2', sans-serif;
  --radius: 12px;
  --radius-lg: 20px;
  --transition: 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: 1rem;
  line-height: 1.6;
  color: var(--text);
  background: var(--bg-deep);
  -webkit-font-smoothing: antialiased;
}

h1, h2, h3, h4 {
  font-family: var(--font-display);
  font-weight: 700;
  letter-spacing: 0.02em;
  margin: 0 0 0.5em;
}

a {
  color: var(--accent-teal);
  text-decoration: none;
  transition: color var(--transition);
}

.section-reveal {
  opacity: 0;
  transform: translateY(24px);
  animation: sectionReveal 0.7s var(--transition) forwards;
}

.btn-cta {
  animation: ctaPulse 2.5s ease-in-out infinite;
}

.card-hover {
  transition: transform var(--transition), box-shadow var(--transition);
}

.card-hover:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.4), 0 0 0 1px var(--accent-teal);
}

.catalog-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr 0.4fr);
  gap: 0.2rem 4rem;
  position: relative;
}

.catalog-grid::before {
  content: '';
  position: absolute;
  inset: -20px;
  border: 3px dashed rgba(251, 191, 36, 0.5);
  pointer-events: none;
}

.noise-overlay::after {
  content: '';
  position: fixed;
  inset: 0;
  background: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.04'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 9999;
  opacity: 0.45;
}
